import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FormBuilder, FormGroup, FormArray, Validators } from '@angular/forms';
import { RecipeService } from '../../../services/recipe.service';
import { Recipe } from '../../../models/models';

@Component({
  selector: 'app-recipe-form',
  templateUrl: './recipe-form.component.html',
  styleUrls: ['./recipe-form.component.css']
})


export class RecipeFormComponent implements OnInit {
  @Input() recipe: Recipe | null = null;
  @Output() saved = new EventEmitter<void>();
  @Output() cancelled = new EventEmitter<void>();

  form: FormGroup;
  loading = false;
  error = '';

  units = ['units', 'g', 'kg', 'ml', 'l', 'tsp', 'tbsp', 'cup'];

  constructor(private fb: FormBuilder, private recipeService: RecipeService) {
    this.form = this.fb.group({
      name: ['', Validators.required],
      description: [''],
      instructions: ['', Validators.required],
      servings: [2, [Validators.required, Validators.min(1)]],
      prep_time_minutes: [30, [Validators.required, Validators.min(0)]],
      is_public: [true],
      ingredients: this.fb.array([])
    });
  }

  ngOnInit(): void {
    if (this.recipe) {
      this.form.patchValue({
        name: this.recipe.name,
        description: this.recipe.description,
        instructions: this.recipe.instructions,
        servings: this.recipe.servings,
        prep_time_minutes: this.recipe.prep_time_minutes,
        is_public: this.recipe.is_public,
      });
      this.recipe.ingredients.forEach(ing => this.addIngredient(ing));
    } else {
      this.addIngredient();
    }
  }

  get ingredients(): FormArray {
    return this.form.get('ingredients') as FormArray;
  }

  addIngredient(data?: { name: string; quantity: number; unit: string }): void {
    this.ingredients.push(this.fb.group({
      name: [data?.name || '', Validators.required],
      quantity: [data?.quantity || 1, [Validators.required, Validators.min(0.01)]],
      unit: [data?.unit || 'units', Validators.required],
    }));
  }

  removeIngredient(index: number): void {
    if (this.ingredients.length > 1) {
      this.ingredients.removeAt(index);
    }
  }

  submit(): void {
    if (this.form.invalid) return;
    this.loading = true;
    this.error = '';
    const data = this.form.value;

    const obs = this.recipe
      ? this.recipeService.update(this.recipe.id, data)
      : this.recipeService.create(data);

    obs.subscribe({
      next: () => { this.loading = false; this.saved.emit(); },
      error: (err) => {
        this.error = Object.values(err.error || {}).flat().join(' ') || 'Failed to save recipe.';
        this.loading = false;
      }
    });
  }
}
<div class="modal-overlay" (click)="cancelled.emit()">
  <div class="modal modal-wide" (click)="$event.stopPropagation()">
    <div class="modal-header">
      <h2>{{ recipe ? 'Edit Recipe' : 'New Recipe' }}</h2>
      <button class="modal-close" (click)="cancelled.emit()">x</button>
    </div>

    <div class="alert alert-danger" *ngIf="error">{{ error }}</div>

    <form [formGroup]="form" (ngSubmit)="submit()">
      <div class="form-group">
        <label>Recipe Name *</label>
        <input class="form-control" formControlName="name" placeholder="e.g. Spaghetti Bolognese"
          [class.is-invalid]="form.get('name')?.invalid && form.get('name')?.touched">
      </div>

      <div class="form-group">
        <label>Description</label>
        <input class="form-control" formControlName="description" placeholder="Short description">
      </div>

      <div class="form-row-3">
        <div class="form-group">
          <label>Servings *</label>
          <input class="form-control" type="number" formControlName="servings" min="1">
        </div>
        <div class="form-group">
          <label>Prep time (min) *</label>
          <input class="form-control" type="number" formControlName="prep_time_minutes" min="0">
        </div>
        <div class="form-group" style="display:flex; align-items:flex-end; padding-bottom:0.1rem">
          <label class="checkbox-label">
            <input type="checkbox" formControlName="is_public">
            Public recipe
          </label>
        </div>
      </div>


      <div class="form-group">
        <div class="ingredients-header">
          <label>Ingredients *</label>
          <button type="button" class="btn btn-sm btn-outline" (click)="addIngredient()">+ Add</button>
        </div>
        <div class="ingredient-rows" formArrayName="ingredients">
          <div class="ingredient-row" *ngFor="let ctrl of ingredients.controls; let i = index"
            [formGroupName]="i">
            <input class="form-control" formControlName="name" placeholder="Ingredient name"
              [class.is-invalid]="ctrl.get('name')?.invalid && ctrl.get('name')?.touched">
            <input class="form-control ing-qty" type="number" formControlName="quantity"
              placeholder="Qty" min="0.01" step="any">
            <select class="form-control ing-unit" formControlName="unit">
              <option *ngFor="let u of units" [value]="u">{{ u }}</option>
            </select>
            <button type="button" class="btn btn-sm btn-danger" (click)="removeIngredient(i)"
              [disabled]="ingredients.length === 1">✕</button>
          </div>
        </div>
      </div>


      <div class="form-group">
        <label>Instructions *</label>
        <textarea class="form-control" formControlName="instructions" rows="6"
          placeholder="1. Step one&#10;2. Step two&#10;3. Step three"
          [class.is-invalid]="form.get('instructions')?.invalid && form.get('instructions')?.touched">
        </textarea>
      </div>

      <div class="modal-footer">
        <button type="button" class="btn btn-secondary" (click)="cancelled.emit()">Cancel</button>
        <button type="submit" class="btn btn-primary" [disabled]="form.invalid || loading">
          {{ loading ? 'Saving...' : (recipe ? 'Update Recipe' : 'Create Recipe') }}
        </button>
      </div>
    </form>
  </div>
</div>
